const PlasmicDescendants = {
  root: [
    "root",
    "reservation",
    "itemBooking",
    "img",
    "section",
    "header",
    "filterIcon2",
    "bookingHeader",
    "dialog",
    "status",
    "uploudeTime",
    "button",
    "filter2"
  ],
  reservation: ["reservation", "itemBooking", "img"],
  itemBooking: ["itemBooking"],
  img: ["img"],
  section: ["section", "header", "filterIcon2", "bookingHeader"],
  header: ["header", "filterIcon2"],
  filterIcon2: ["filterIcon2"],
  bookingHeader: ["bookingHeader"],
  dialog: ["dialog", "status", "uploudeTime", "button"],
  status: ["status"],
  uploudeTime: ["uploudeTime"],
  button: ["button"],
  filter2: ["filter2"]
} as const;
type NodeNameType = keyof typeof PlasmicDescendants;
type DescendantsType<T extends NodeNameType> =
  (typeof PlasmicDescendants)[T][number];
type NodeDefaultElementType = {
  root: "div";
  reservation: typeof ApiRequest;
  itemBooking: typeof ItemBooking;
  img: typeof PlasmicImg__;
  section: "section";
  header: typeof Header;
  filterIcon2: typeof FilterIcon2;
  bookingHeader: typeof BookingHeader;
  dialog: typeof Dialog;
  status: typeof Status;
  uploudeTime: typeof UploudeTime;
  button: typeof Button;
  filter2: typeof Filter2;
};

type ReservedPropsType = "variants" | "args" | "overrides";
type NodeOverridesType<T extends NodeNameType> = Pick<
  PlasmicBooking__OverridesType,
  DescendantsType<T>
>;
type NodeComponentProps<T extends NodeNameType> =
  // Explicitly specify variants, args, and overrides as objects
  {
    variants?: PlasmicBooking__VariantsArgs;
    args?: PlasmicBooking__ArgsType;
    overrides?: NodeOverridesType<T>;
  } &
    // Specify variants directly as props
    Omit<PlasmicBooking__VariantsArgs, ReservedPropsType> &
    // Specify args directly as props
    Omit<PlasmicBooking__ArgsType, ReservedPropsType> &
    // Specify overrides for each element directly as props
    Omit<
      NodeOverridesType<T>,
      ReservedPropsType | VariantPropType | ArgPropType
    > &
    // Specify props for the root element
    Omit<
      Partial<React.ComponentProps<NodeDefaultElementType[T]>>,
      ReservedPropsType | VariantPropType | ArgPropType | DescendantsType<T>
    >;

function makeNodeComponent<NodeName extends NodeNameType>(nodeName: NodeName) {
  type PropsType = NodeComponentProps<NodeName> & { key?: React.Key };
  const func = function <T extends PropsType>(
    props: T & StrictProps<T, PropsType>
  ) {
    const { variants, args, overrides } = React.useMemo(
      () =>
        deriveRenderOpts(props, {
          name: nodeName,
          descendantNames: PlasmicDescendants[nodeName],
          internalArgPropNames: PlasmicBooking__ArgProps,
          internalVariantPropNames: PlasmicBooking__VariantProps
        }),
      [props, nodeName]
    );
    return PlasmicBooking__RenderFunc({
      variants,
      args,
      overrides,
      forNode: nodeName
    });
  };
  if (nodeName === "root") {
    func.displayName = "PlasmicBooking";
  } else {
    func.displayName = `PlasmicBooking.${nodeName}`;
  }
  return func;
}

export const PlasmicBooking = Object.assign(
  // Top-level PlasmicBooking renders the root element
  makeNodeComponent("root"),
  {
    // Helper components rendering sub-elements
    reservation: makeNodeComponent("reservation"),
    itemBooking: makeNodeComponent("itemBooking"),
    img: makeNodeComponent("img"),
    section: makeNodeComponent("section"),
    header: makeNodeComponent("header"),
    filterIcon2: makeNodeComponent("filterIcon2"),
    bookingHeader: makeNodeComponent("bookingHeader"),
    dialog: makeNodeComponent("dialog"),
    status: makeNodeComponent("status"),
    uploudeTime: makeNodeComponent("uploudeTime"),
    button: makeNodeComponent("button"),
    filter2: makeNodeComponent("filter2"),

    // Metadata about props expected for PlasmicBooking
    internalVariantProps: PlasmicBooking__VariantProps,
    internalArgProps: PlasmicBooking__ArgProps
  }
);

export default PlasmicBooking;
